SET client_encoding TO 'UTF8';

SET check_function_bodies = false;





CREATE OR REPLACE FUNCTION fpa_cnv2oldcon (as_newcon text) RETURNS varchar AS $body$
DECLARE

  ls_loantype char(2);
  ls_conrun varchar(100);
  ls_year varchar(10);
  ls_extend varchar(10);

BEGIN
  case substr(as_newcon,1,2)
    when 'สม'then ls_loantype := 'ส0';
    when 'สน'then ls_loantype := 'สน';
    when 'สค'then ls_loantype := 'สค';
    when 'ฉฉ'then ls_loantype := 'ฉ0';
    else ls_loantype := 'XX';
  end case;

  ls_conrun := trim(both to_char((substr(as_newcon,5,6))::numeric ,'00000')); -- สม53000018-9
  ls_year   := '25'||substr(as_newcon,3,2);
  ls_extend := substr(as_newcon,11);

  RETURN ls_loantype||ls_conrun||ls_extend||'/'||ls_year;
exception when others then CALL spa_dberror('('||trim(both as_newcon)||')');
END;
$body$
LANGUAGE PLPGSQL
SECURITY DEFINER
;
